import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

/**
 * Hàm cn kết hợp giữa:
 * 1. clsx: Cho phép truyền class theo kiểu object, array, conditional (true/false)
 * 2. tailwind-merge: Đảm bảo các class Tailwind sau cùng sẽ ghi đè các class trước đó một cách chính xác
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

@import "tailwindcss";
@plugin "tailwindcss-animate";
@custom-variant dark (&:where(.dark, .dark *));

/*
  View Transitions API: Tắt animation mặc định (fade cross-dissolve).
  ThemeToggle sẽ tự định nghĩa clip-path ripple animation thay thế.
*/
::view-transition-old(root),
::view-transition-new(root) {
    animation: none;
    mix-blend-mode: normal;
}

::view-transition-old(root) {
    z-index: 1;
}

::view-transition-new(root) {
    z-index: 9999;
}


@theme {
  --animate-ping: ping 1.5s linear infinite; /* Chỉnh cho nó chạy chậm lại */



    --color-background: var(--background);
    --color-foreground: var(--foreground);

    --color-primary: var(--primary);
    --color-primary-foreground: var(--primary-foreground);

    --color-secondary: var(--secondary);
    --color-secondary-foreground: var(--secondary-foreground);

    --color-muted: var(--muted);
    --color-muted-foreground: var(--muted-foreground);

    --color-accent: var(--accent);
    --color-accent-foreground: var(--accent-foreground);

    --color-switch-background: var(--switch-background);

    --color-border: var(--border);

    --color-success: var(--success);
    --color-success-foreground: var(--success-foreground);

    --color-warning: var(--warning);
    --color-warning-foreground: var(--warning-foreground);

    --color-destructive: var(--danger);
    --color-destructive-foreground: var(--danger-foreground);

    --color-danger: var(--danger);
    --color-danger-foreground: var(--danger-foreground);

    --color-ring: var(--ring);
    --color-input: var(--input);

    --color-chart-1: var(--chart-1);
    --color-chart-2: var(--chart-2);
    --color-chart-3: var(--chart-3);
    --color-chart-4: var(--chart-4);
    --color-chart-5: var(--chart-5);

    --color-popover: var(--popover);
    --color-popover-foreground: var(--popover-foreground);

    --color-sidebar: var(--sidebar);
    --color-sidebar-foreground: var(--sidebar-foreground);
    --color-sidebar-border: var(--sidebar-border);
    --color-sidebar-accent: var(--sidebar-accent);
    --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
    --color-sidebar-ring: var(--sidebar-ring);

    --radius-sm: 0.125rem;
    --radius-md: 0.375rem;
    --radius-lg: 0.5rem;
    --radius-xl: 1rem;

    --animate-spin-slow: spin 3s linear infinite;
    --animate-progress-stripes: progress-stripes 1s linear infinite;

    @keyframes progress-stripes {
        from { background-position: 1rem 0; }
        to { background-position: 0 0; }
    }
}

@layer base {
    :root {
        /* Light Theme - Clean White */
        --background: #ffffff;
        --foreground: #0f172a;
        
        --primary: #2f27ce;
        --primary-foreground: #ffffff;
        
        --secondary: #dedcff; /* Vẫn giữ nét màu Light cũ nhưng tinh chỉnh nhẹ */
        --secondary-foreground: #2f27ce;
        
        --muted: #f8fafc;
        --muted-foreground: #64748b;
        
        --accent: #f1f5f9;
        --accent-foreground: #0f172a;
        
        --switch-background: #cbd5e1;
        --border: #e2e8f0;
        
        --success: #10b981;
        --success-foreground: #ffffff;
        
        --warning: #f59e0b;
        --warning-foreground: #ffffff;
        
        --danger: #ef4444;
        --danger-foreground: #ffffff;

        --popover: #ffffff;
        --popover-foreground: #0f172a;

        --sidebar: #f8fafc;
        --sidebar-foreground: #0f172a;
        --sidebar-border: #7a7a7a;
        --sidebar-accent: #f1f5f9;
        --sidebar-accent-foreground: #2f27ce;
        --sidebar-ring: #2f27ce;
    }

    .dark {
        /* Dark Theme - Deep Space Slate (Chuyên nghiệp & Hiện đại) */
        --background: #09090b; /* Very deep zinc/slate */
        --foreground: #f8fafc;
        
        --primary: #6366f1; /* Bright Indigo for pop */
        --primary-foreground: #ffffff;
        
        --secondary: #1e293b; /* Slate 800 */
        --secondary-foreground: #f8fafc;
        
        --muted: #0f172a; /* Slate 900 for subdued bg */
        --muted-foreground: #94a3b8; /* Slate 400 for text */
        
        --accent: #1e293b;
        --accent-foreground: #f8fafc;
        
        --switch-background: #334155;
        --border: #334155; /* Slate 700 */
        
        --success: #10b981;
        --success-foreground: #ffffff;
        
        --warning: #f59e0b;
        --warning-foreground: #ffffff;
        
        --danger: #ef4444;
        --danger-foreground: #ffffff;

        --ring: #6366f1;
        --input: #334155;

        --chart-1: #fb7185;
        --chart-2: #6366f1;
        --chart-3: #34d399;
        --chart-4: #fbbf24;
        --chart-5: #818cf8;

        --popover: #0f172a;
        --popover-foreground: #f8fafc;

        --sidebar: #0f172a;
        --sidebar-foreground: #f8fafc;
        --sidebar-border: #334155;
        --sidebar-accent: #1e293b;
        --sidebar-accent-foreground: #818cf8;
        --sidebar-ring: #6366f1;
    }
}


@layer base {
    * {
        border-color: var(--border);
    }

    html, body {
        margin: 0;
        padding: 0;
        background-color: var(--background);
        color: var(--foreground);
        font-family: 'Inter', system-ui, sans-serif;
        overflow: hidden; /* Khóa scroll tổng để dùng nội bộ */
        height: 100%;
        color-scheme: light;
        transition: background-color 0.3s ease, color 0.3s ease;
    }

    html.dark {
        color-scheme: dark;
    }

    /* Fix dải trắng khi mở modal/dialog trong các thư viện (Base UI, Radix) */
    body[style*="overflow: hidden"],
    body[data-scroll-locked] {
        padding-right: 0 !important;
        margin-right: 0 !important;
    }

    /* Đảm bảo Backdrop luôn phủ kín màn hình bất chấp các tính toán của thư viện */
    [data-base-ui-dialog-backdrop],
    .base-ui-backdrop,
    [role="presentation"] > div[style*="fixed"] {
        width: 100vw !important;
        height: 100vh !important;
        left: 0 !important;
        top: 0 !important;
        right: 0 !important;
        bottom: 0 !important;
    }

    /* Custom Scrollbar - Sleek & Modern */
    ::-webkit-scrollbar {
        width: 8px;
        height: 8px;
    }

    ::-webkit-scrollbar-track {
        background: transparent;
    }

    ::-webkit-scrollbar-thumb {
        background: #cbd5e1; /* slate-300 */
        border-radius: 10px;
        border: 2px solid transparent;
        background-clip: content-box;
    }

    .dark ::-webkit-scrollbar-thumb {
        background: #334155; /* slate-700 */
    }

    ::-webkit-scrollbar-thumb:hover {
        background: #94a3b8; /* slate-400 */
        background-clip: content-box;
    }

    .dark ::-webkit-scrollbar-thumb:hover {
        background: #475569; /* slate-600 */
    }

    /* Firefox */
    * {
        scrollbar-width: thin;
        scrollbar-color: #cbd5e1 transparent;
    }

    .dark * {
        scrollbar-color: #334155 transparent;
    }
}

/* Ensure data-state="checked" always works for background */
[data-state="checked"] {
    &.bg-primary {
        background-color: var(--primary);
    }
}

[data-state="indeterminate"] {
    &.bg-primary {
        background-color: var(--primary);
    }
}

import * as React from 'react';
import { Accordion as BaseAccordion } from '@base-ui/react';
import { ChevronDown } from 'lucide-react';
import { tv } from 'tailwind-variants';

const accordionVariants = tv({
  slots: {
    root: 'w-full',
    item: 'border-b border-border/50 last:border-0',
    header: 'flex',
    trigger: 'flex flex-1 items-center justify-between py-4 text-sm font-medium transition-all hover:text-primary hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 [&[data-panel-open]>svg]:rotate-180',
    panel: 'overflow-hidden text-sm data-[open]:animate-accordion-down data-[closed]:animate-accordion-up transition-all',
  }
});

const { root, item, header, trigger, panel } = accordionVariants();

export const Accordion = React.forwardRef<React.ElementRef<typeof BaseAccordion.Root>, Omit<React.ComponentPropsWithoutRef<typeof BaseAccordion.Root>, 'className'> & { className?: string }>(
  ({ className, ...props }, ref) => (
    <BaseAccordion.Root ref={ref} className={root({ className })} {...props} />
  )
)
Accordion.displayName = 'Accordion';

export const AccordionItem = React.forwardRef<React.ElementRef<typeof BaseAccordion.Item>, Omit<React.ComponentPropsWithoutRef<typeof BaseAccordion.Item>, 'className'> & { className?: string }>(
  ({ className, ...props }, ref) => (
    <BaseAccordion.Item ref={ref} className={item({ className })} {...props} />
  )
)
AccordionItem.displayName = 'AccordionItem';

export const AccordionTrigger = React.forwardRef<React.ElementRef<typeof BaseAccordion.Trigger>, Omit<React.ComponentPropsWithoutRef<typeof BaseAccordion.Trigger>, 'className'> & { className?: string; hideChevron?: boolean }>(
  ({ className, children, hideChevron, ...props }, ref) => (
    <BaseAccordion.Header className={header()}>
      <BaseAccordion.Trigger ref={ref} className={trigger({ className })} {...props}>
        {children}
        {!hideChevron && <ChevronDown className="h-4 w-4 shrink-0 transition-transform duration-200" />}
      </BaseAccordion.Trigger>
    </BaseAccordion.Header>
  )
)
AccordionTrigger.displayName = 'AccordionTrigger';

export const AccordionContent = React.forwardRef<React.ElementRef<typeof BaseAccordion.Panel>, Omit<React.ComponentPropsWithoutRef<typeof BaseAccordion.Panel>, 'className'> & { className?: string }>(
  ({ className, children, ...props }, ref) => (
    <BaseAccordion.Panel ref={ref} className={panel({ className })} {...props}>
      <div className="pb-4 pt-0">{children}</div>
    </BaseAccordion.Panel>
  )
)
AccordionContent.displayName = 'AccordionContent';

import * as React from 'react';
import { AlertCircle, CheckCircle2, ChevronRight, Info, XCircle } from 'lucide-react';
import { tv, type VariantProps } from 'tailwind-variants';
import { cn } from '@lib/utils/cn';

const alertVariants = tv({
  base: 'relative w-full rounded-lg border p-4 [&>svg~*]:pl-7 [&>svg+div]:translate-y-[-3px] [&>svg]:absolute [&>svg]:left-4 [&>svg]:top-4 [&>svg]:text-foreground',
  variants: {
    variant: {
      default: 'bg-background text-foreground',
      destructive: 'border-destructive/50 text-destructive dark:border-destructive [&>svg]:text-destructive',
      success: 'border-success/50 text-success dark:border-success [&>svg]:text-success',
      warning: 'border-warning/50 text-warning dark:border-warning [&>svg]:text-warning',
      info: 'border-blue-500/50 text-blue-500 dark:border-blue-500 [&>svg]:text-blue-500',
    }
  },
  defaultVariants: {
    variant: 'default'
  }
});

const Alert = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement> & VariantProps<typeof alertVariants>>(
  ({ className, variant, ...props }, ref) => (
    <div
      ref={ref}
      role="alert"
      className={alertVariants({ variant, className })}
      {...props}
    />
  )
);
Alert.displayName = 'Alert';

const AlertTitle = React.forwardRef<HTMLParagraphElement, React.HTMLAttributes<HTMLHeadingElement>>(
  ({ className, ...props }, ref) => (
    <h5
      ref={ref}
      className={cn('mb-1 font-medium leading-none tracking-tight', className)}
      {...props}
    />
  )
);
AlertTitle.displayName = 'AlertTitle';

const AlertDescription = React.forwardRef<HTMLParagraphElement, React.HTMLAttributes<HTMLParagraphElement>>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      className={cn('text-sm [&_p]:leading-relaxed', className)}
      {...props}
    />
  )
);
AlertDescription.displayName = 'AlertDescription';

export { Alert, AlertTitle, AlertDescription };

import * as React from 'react';
import { AlertDialog as BaseAlertDialog } from '@base-ui/react';
import { tv } from 'tailwind-variants';

const alertDialogVariants = tv({
  slots: {
    overlay: 'fixed inset-0 z-50 bg-black/50 backdrop-blur-sm data-starting:animate-in data-ending:animate-out data-ending:fade-out-0 data-starting:fade-in-0',
    content: 'fixed left-[50%] top-[50%] z-50 grid w-full max-w-lg translate-x-[-50%] translate-y-[-50%] gap-4 border border-border bg-background p-6 shadow-lg duration-200 data-starting:animate-in data-ending:animate-out data-ending:fade-out-0 data-starting:fade-in-0 data-ending:zoom-out-95 data-starting:zoom-in-95 sm:rounded-lg',
    header: 'flex flex-col space-y-2 text-center sm:text-left',
    footer: 'flex flex-col-reverse sm:flex-row sm:justify-end sm:space-x-2 mt-2',
    title: 'text-lg font-semibold leading-none tracking-tight',
    description: 'text-sm text-muted-foreground',
  }
});

const { overlay, content, header, footer, title, description } = alertDialogVariants();

export interface AlertDialogProps extends React.ComponentPropsWithoutRef<typeof BaseAlertDialog.Root> {
  trigger?: React.ReactNode;
  headerTitle?: string;
  headerDescription?: string;
  cancelContent?: React.ReactNode;
  actionContent?: React.ReactNode;
}

const AlertDialog = React.forwardRef<React.ElementRef<typeof BaseAlertDialog.Root>, AlertDialogProps>(
  ({ trigger, headerTitle, headerDescription, cancelContent, actionContent, ...props }, ref) => {
    return (
      <BaseAlertDialog.Root {...props}>
        {trigger && <BaseAlertDialog.Trigger render={trigger as React.ReactElement} />}
        <BaseAlertDialog.Portal>
          <BaseAlertDialog.Backdrop className={overlay()} />
          <BaseAlertDialog.Popup className={content()}>
            {(headerTitle || headerDescription) && (
              <div className={header()}>
                {headerTitle && <BaseAlertDialog.Title className={title()}>{headerTitle}</BaseAlertDialog.Title>}
                {headerDescription && <BaseAlertDialog.Description className={description()}>{headerDescription}</BaseAlertDialog.Description>}
              </div>
            )}
            
            <div className={footer()}>
                {cancelContent && (
                    <BaseAlertDialog.Close render={cancelContent as React.ReactElement} />
                )}
                {actionContent && (
                    actionContent
                )}
            </div>
          </BaseAlertDialog.Popup>
        </BaseAlertDialog.Portal>
      </BaseAlertDialog.Root>
    );
  }
);

AlertDialog.displayName = 'AlertDialog';

export { AlertDialog };

import * as React from 'react';
import { tv, type VariantProps } from 'tailwind-variants';

const avatarVariants = tv({
  base: 'relative flex shrink-0 overflow-hidden rounded-full items-center justify-center bg-secondary text-secondary-foreground outline-none',
  variants: {
    size: {
      sm: 'h-8 w-8 text-xs',
      md: 'h-10 w-10 text-sm',
      lg: 'h-12 w-12 text-base',
      xl: 'h-16 w-16 text-lg',
    },
  },
  defaultVariants: {
    size: 'md',
  },
});

export interface AvatarProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof avatarVariants> {
  src?: string;
  alt?: string;
  fallback?: string;
}

const Avatar = React.forwardRef<HTMLDivElement, AvatarProps>(
  ({ className, size, src, alt, fallback, ...props }, ref) => {
    const [hasError, setHasError] = React.useState(false);

    return (
      <div ref={ref} className={avatarVariants({ size, className })} {...props}>
        {src && !hasError ? (
          <img
            src={src}
            alt={alt || "Avatar"}
            className="aspect-square h-full w-full object-cover"
            onError={() => setHasError(true)}
          />
        ) : (
          <span className="font-medium uppercase tracking-wider">
            {fallback || (alt ? alt.substring(0, 2) : '??')}
          </span>
        )}
      </div>
    );
  }
);
Avatar.displayName = 'Avatar';

export { Avatar };

import * as React from 'react';
import { tv, type VariantProps } from 'tailwind-variants';

const badgeVariants = tv({
  base: 'inline-flex items-center justify-center rounded-full border px-2.5 py-0.5 font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2 w-fit',
  variants: {
    variant: {
      default: 'border-transparent bg-primary text-primary-foreground shadow-sm',
      secondary: 'border-transparent bg-secondary text-secondary-foreground shadow-sm',
      outline: 'border-border text-foreground hover:bg-muted',
      success: 'border-transparent bg-success text-success-foreground shadow-sm',
      warning: 'border-transparent bg-warning text-warning-foreground shadow-sm',
      danger: 'border-transparent bg-danger text-danger-foreground shadow-sm',

      // Soft variants
      'soft-primary': 'border-transparent bg-primary/10 text-primary',
      'soft-success': 'border-transparent bg-success/10 text-success',
      'soft-warning': 'border-transparent bg-warning/10 text-warning',
      'soft-danger': 'border-transparent bg-danger/10 text-danger',

      // Glass variant
      glass: 'border border-white/20 bg-white/10 text-foreground backdrop-blur-md shadow-sm',

      // Gradient variant
      gradient: 'border-transparent bg-gradient-to-r from-primary to-indigo-500 text-white shadow-sm',
    },
    size: {
      sm: 'text-[10px] px-2 py-0.5 leading-4',
      md: 'text-xs px-2.5 py-0.5 leading-5',
      lg: 'text-sm px-3 py-1 leading-6',
    }
  },
  defaultVariants: {
    variant: 'default',
    size: 'md',
  }
});

export interface BadgeProps
  extends React.HTMLAttributes<HTMLSpanElement>,
  VariantProps<typeof badgeVariants> {
  pulse?: boolean;
}

const Badge = React.forwardRef<HTMLSpanElement, BadgeProps>(
  ({ className, variant, size, pulse, children, ...props }, ref) => {
    return (
      <span ref={ref} className={badgeVariants({ variant, size, className })} {...props}>
        {pulse && (
          <span className="relative grid place-items-center h-2 w-2 mr-1.5">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-current opacity-75"></span>
            <span className="relative inline-flex rounded-full h-1.5 w-1.5 bg-current"></span>
          </span>
        )}
        {children}
      </span>
    );
  }
);
Badge.displayName = 'Badge';

export { Badge, badgeVariants };

import { render, screen } from '@testing-library/react';
import { describe, it, expect } from 'vitest';
import { Button } from './Button';

describe('Button', () => {
  it('renders correctly with default props', () => {
    render(<Button>Click me</Button>);
    const button = screen.getByRole('button', { name: /click me/i });
    expect(button).toBeInTheDocument();
  });

  it('renders loading spinner when isLoading is true', () => {
    render(<Button isLoading>Submit</Button>);
    const button = screen.getByRole('button', { name: /submit/i });

    // Nút phải bị disable
    expect(button).toBeDisabled();

    // Spinner (có role="status") phải xuất hiện
    const spinner = screen.getByRole('status');
    expect(spinner).toBeInTheDocument();
  });

  it('renders correctly with different variants', () => {
    const { container } = render(<Button variant="danger">Delete</Button>);
    const button = container.firstChild as HTMLElement;
    expect(button.className).toContain('bg-danger');
  });
});

import * as React from 'react';
import { Button as BaseButton } from '@base-ui/react';
import { tv, type VariantProps } from 'tailwind-variants';
import { Spinner } from '../spinner/Spinner';

const buttonVariants = tv({
  base: 'inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:opacity-30 disabled:hover:bg-transparent data-open:bg-muted cursor-pointer disabled:cursor-not-allowed',
  variants: {
    variant: {
      solid: 'bg-primary text-primary-foreground hover:bg-primary/70 shadow-sm',
      outline: 'border border-border bg-transparent hover:bg-secondary/90 hover:text-foreground',
      ghost: 'hover:bg-secondary/90 hover:text-foreground',
      secondary: 'bg-secondary text-secondary-foreground hover:bg-secondary/70 shadow-sm',
      danger: 'bg-danger text-danger-foreground hover:bg-danger/70 shadow-sm',
      link: 'text-primary underline-offset-4 hover:underline h-auto px-0 py-0 font-normal',
      // Kính mờ tối — trên nền tối
      glass: 'bg-white/15 backdrop-blur-md border border-white/30 text-white hover:bg-white/25 hover:border-white/50 shadow-[inset_0_1px_0_rgba(255,255,255,0.7),0_4px_20px_rgba(0,0,0,0.2)] transition-all',
      // ─── Glossy Bubble Variants ───────────────────────────────────────────────
      // Gradient from white highlight (top-left) → tinted color (bottom-right)
      // + inset top border = hiệu ứng gương bong bóng xà phòng
     'glass-white': 'bg-gradient-to-br from-white/70 to-slate-100/60 backdrop-blur-md border border-black/5 text-slate-700 hover:from-white/85 hover:to-slate-100/70 shadow-[0_4px_12px_rgba(0,0,0,0.1),inset_0_1px_0_rgba(255,255,255,0.8)] transition-all',
      'glass-amber': 'bg-gradient-to-br from-white/70 to-amber-300/40 backdrop-blur-sm border border-amber-100/80 text-amber-700 hover:from-white/85 hover:to-amber-300/60 shadow-[0_4px_12px_rgba(0,0,0,0.1),inset_0_1px_0_rgba(255,255,255,0.8)] transition-all',
      'glass-green': 'bg-gradient-to-br from-white/70 to-emerald-300/40 backdrop-blur-sm border border-emerald-100/80 text-emerald-700 hover:from-white/85 hover:to-emerald-300/60 shadow-[0_4px_12px_rgba(0,0,0,0.1),inset_0_1px_0_rgba(255,255,255,0.8)] transition-all',
      'glass-purple': 'bg-gradient-to-br from-white/70 to-violet-300/40 backdrop-blur-sm border border-violet-100/80 text-violet-700 hover:from-white/85 hover:to-violet-300/60 shadow-[0_4px_12px_rgba(0,0,0,0.1),inset_0_1px_0_rgba(255,255,255,0.8)] transition-all',
      'glass-pink': 'bg-gradient-to-br from-white/70 to-pink-300/40 backdrop-blur-sm border border-pink-100/80 text-pink-700 hover:from-white/85 hover:to-pink-300/60 shadow-[0_4px_12px_rgba(0,0,0,0.1),inset_0_1px_0_rgba(255,255,255,0.8)] transition-all',
    },
    size: {
      sm: 'h-8 px-3 text-xs',
      md: 'h-10 px-4 py-2',
      lg: 'h-11 px-8',
      icon: 'h-10 w-10',
    },
  },
  defaultVariants: {
    variant: 'solid',
    size: 'md',
  },
});

export interface ButtonProps
  extends Omit<React.ComponentPropsWithoutRef<typeof BaseButton>, 'className'>,
  VariantProps<typeof buttonVariants> {
  leftIcon?: React.ReactNode;
  rightIcon?: React.ReactNode;
  isLoading?: boolean;
  className?: string;
  children?: React.ReactNode;
}

const Button = React.forwardRef<React.ElementRef<typeof BaseButton>, ButtonProps>(
