import * as React from 'react';
import { Combobox as BaseCombobox } from '@base-ui/react';
import { Check, ChevronDown, X, Loader2 } from 'lucide-react';
import { tv } from 'tailwind-variants';
import { cn } from '@lib/utils/cn';

const comboboxVariants = tv({
  slots: {
    root: 'flex flex-col gap-1.5 w-full',
    inputContainer: 'flex flex-wrap items-center gap-1.5 min-h-10 w-full rounded-md border border-border bg-background px-3 py-1.5 text-sm focus-within:border-primary disabled:cursor-not-allowed disabled:opacity-50 transition-shadow transition-colors',
    input: 'flex-1 min-w-[120px] bg-transparent outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed',
    popup: 'z-50 w-[var(--anchor-width,var(--reference-width))] max-w-[var(--available-width)] overflow-hidden rounded-md border border-border bg-background text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95 data-side-bottom:slide-in-from-top-2 data-side-left:slide-in-from-right-2 data-side-right:slide-in-from-left-2 data-side-top:slide-in-from-bottom-2',
    item: 'cursor-pointer relative flex w-full cursor-default select-none items-center rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none data-highlighted:bg-accent data-highlighted:text-accent-foreground data-disabled:pointer-events-none data-disabled:opacity-50',
    indicator: 'absolute left-2 flex h-3.5 w-3.5 items-center justify-center',
    chip: 'inline-flex items-center gap-1 rounded bg-secondary px-2 py-0.5 text-xs font-medium text-secondary-foreground outline-none focus:ring-1 focus:ring-primary',
    chipRemove: 'hover:bg-primary/20 rounded-full p-0.5 transition-colors cursor-pointer',
    actionsHeader: 'flex items-center gap-1 p-1 border-b border-border sticky top-0 bg-background z-10',
    actionButton: 'flex-1 text-[10px] uppercase tracking-wider font-bold py-1.5 px-2 rounded-sm hover:bg-accent hover:text-accent-foreground text-muted-foreground transition-colors text-center',
  }
});

export interface ComboBoxOption {
  label: string;
  value: string;
}

export interface ComboBoxProps {
  options: ComboBoxOption[];
  label?: string;
  placeholder?: string;
  value?: string | string[];
  defaultValue?: string | string[];
  onValueChange?: (value: string | string[]) => void;
  multiple?: boolean;
  isLoading?: boolean;
  className?: string;
  autocomplete?: boolean;
  emptyText?: string;
  selectAllText?: string;
  clearAllText?: string;
  leftIcon?: React.ReactNode;
}

const ComboBox = React.forwardRef<HTMLInputElement, ComboBoxProps>(
  ({ options, label, placeholder, value, defaultValue, onValueChange, multiple, isLoading, className, autocomplete = true, emptyText = 'Không tìm thấy kết quả.', selectAllText = 'Chọn tất cả', clearAllText = 'Xóa tất cả', leftIcon }, ref) => {
    const [inputValue, setInputValue] = React.useState('');
    const [internalValue, setInternalValue] = React.useState<string | string[] | null>(defaultValue || (multiple ? [] : null));

    const activeValue = value !== undefined ? value : internalValue;

    const handleValueChange = (newVal: string | string[] | null) => {
      if (value === undefined) {
        setInternalValue(newVal);
      }
      if (newVal !== null) {
        onValueChange?.(newVal);
      }
    };

    const handleClear = (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      handleValueChange(multiple ? [] : null);
      setInputValue('');
    };

    const hasValue = multiple
      ? Array.isArray(activeValue) && activeValue.length > 0
      : !!activeValue;

    // Lọc options theo text người dùng đang gõ
    const filteredOptions = React.useMemo(() => {
      if (!inputValue || !autocomplete) return options;
      // Khi đã có value được chọn, input hiển thị label → không filter theo label đó
      if (!multiple && activeValue) {
        const selectedOption = options.find((o) => o.value === activeValue);
        if (selectedOption && inputValue === selectedOption.label) return options;
      }
      return options.filter(opt =>
        opt.label.toLowerCase().includes(inputValue.toLowerCase())
      );
    }, [options, inputValue, autocomplete, multiple, activeValue]);

    const { root, inputContainer, input, popup, item, indicator, chip, chipRemove, actionsHeader, actionButton } = comboboxVariants();
    const inputGroupRef = React.useRef<HTMLDivElement>(null);

    return (
      <BaseCombobox.Root
        value={activeValue}
        onValueChange={handleValueChange}
        multiple={multiple}
        onInputValueChange={setInputValue}
        autoHighlight
        itemToStringLabel={(val: string) => options.find((o) => o.value === val)?.label ?? val}
      >
        <div className={root({ className })}>
          {label && <label className="text-sm font-medium text-foreground">{label}</label>}

          <div className="relative w-full group">
            <BaseCombobox.InputGroup ref={inputGroupRef} className={cn(inputContainer(), leftIcon && 'pl-9')}>
              {leftIcon && (
                <div className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground group-focus-within:text-primary transition-colors pointer-events-none">
                  {leftIcon}
                </div>
              )}
              {multiple ? (
                <BaseCombobox.Chips className="flex flex-wrap items-center gap-1.5 flex-1 w-full min-w-0">
                  {Array.isArray(activeValue) && activeValue.map((val) => {
                    const option = options.find(o => o.value === val);
                    return (
                      <BaseCombobox.Chip key={val} className={chip()}>
                        {option?.label || val}
                        <BaseCombobox.ChipRemove className={chipRemove()}>
                          <X className="h-3 w-3" />
                        </BaseCombobox.ChipRemove>
                      </BaseCombobox.Chip>
                    );
                  })}
                  <BaseCombobox.Input
                    ref={ref}
                    readOnly={!autocomplete}
                    placeholder={Array.isArray(activeValue) && activeValue.length > 0 ? '' : placeholder}
                    className={input()}
                  />
                </BaseCombobox.Chips>
              ) : (
                <BaseCombobox.Input
                  ref={ref}
                  readOnly={!autocomplete}
                  placeholder={placeholder}
                  className={cn(input(), !autocomplete && 'cursor-pointer')}
                />
              )}

              {hasValue && (
                <button
                  type="button"
                  onClick={handleClear}
                  className="p-1 hover:bg-muted rounded-full text-muted-foreground transition-colors mr-1"
                >
                  <X className="h-3.5 w-3.5" />
                </button>
              )}

              <BaseCombobox.Trigger className="text-muted-foreground transition-transform group-data-open:rotate-180 ml-auto">
                {isLoading ? <Loader2 className="h-4 w-4 animate-spin" /> : <ChevronDown className="h-4 w-4" />}
              </BaseCombobox.Trigger>
            </BaseCombobox.InputGroup>

            <BaseCombobox.Portal>
              <BaseCombobox.Positioner
                anchor={inputGroupRef}
                sideOffset={4}
                style={{ width: 'var(--anchor-width)' }}
              >
                <BaseCombobox.Popup className={cn(popup(), 'min-w-0')}>
                  {multiple && options.length > 0 && (
                    <div className={actionsHeader()}>
                      <button
                        type="button"
                        aria-label={selectAllText}
                        onClick={(e) => {
                          e.preventDefault();
                          handleValueChange(options.map((o) => o.value));
                        }}
                        className={actionButton()}
                      >
                        {selectAllText}
                      </button>
                      <div className="w-px h-3 bg-border" />
                      <button
                        type="button"
                        aria-label={clearAllText}
                        onClick={(e) => {
                          e.preventDefault();
                          handleValueChange([]);
                        }}
                        className={actionButton()}
                      >
                        {clearAllText}
                      </button>
                    </div>
                  )}
                  <BaseCombobox.List className="p-1 max-h-[300px] overflow-auto">
                    {filteredOptions.length === 0 ? (
                      <div className="py-2 px-8 text-sm text-muted-foreground italic">{emptyText}</div>
                    ) : (
                      filteredOptions.map((option) => (
                        <BaseCombobox.Item
                          key={option.value}
                          value={option.value}
                          className={item()}
                        >
                          <BaseCombobox.ItemIndicator className={indicator()}>
                            <Check className="h-4 w-4" />
                          </BaseCombobox.ItemIndicator>
                          {option.label}
                        </BaseCombobox.Item>
                      ))
                    )}
                  </BaseCombobox.List>
                </BaseCombobox.Popup>
              </BaseCombobox.Positioner>
            </BaseCombobox.Portal>
          </div>
        </div>
      </BaseCombobox.Root>
    );
  }
);

ComboBox.displayName = 'ComboBox';

export { ComboBox };

import * as React from 'react';
import { Popover as BasePopover } from '@base-ui/react';
import { DayPicker, type DateRange } from 'react-day-picker';
import { format } from 'date-fns';
import { Calendar as CalendarIcon, ChevronDown, Clock } from 'lucide-react';
import { tv } from 'tailwind-variants';
import * as locales from 'react-day-picker/locale';

import 'react-day-picker/dist/style.css';
import { Button } from '../button/Button';

// ---------- types ----------

export type TimeFormat = 'HH' | 'HH:mm' | 'HH:mm:ss';
export type DatePickerMode = 'single' | 'range' | 'time-only';
export type TimePickerStyle = 'input' | 'select';

interface TimeParts {
    h: string;
    m: string;
    s: string;
}

export interface DatePickerProps {
    mode?: DatePickerMode;
    /** single → Date | range → DateRange | time-only → dùng timeValue */
    date?: Date | DateRange;
    onDateChange?: (date: Date | DateRange | undefined) => void;
    onChange?: (date: Date | DateRange | undefined) => void;
    /** Chỉ dùng khi mode='time-only' */
    timeValue?: string;
    onTimeChange?: (time: string) => void;
    label?: string;
    placeholder?: string;
    disablePastDates?: boolean;
    showTime?: boolean;
    timeFormat?: TimeFormat;
    timePickerStyle?: TimePickerStyle;
    disabled?: boolean;
    className?: string;
    description?: string;
    error?: string;
}

// ---------- helpers ----------

const DEFAULT_TIME: TimeParts = { h: '00', m: '00', s: '00' };

function parseTimeParts(timeStr: string): TimeParts {
    const [h = '00', m = '00', s = '00'] = timeStr.split(':');
    return {
        h: h.padStart(2, '0'),
        m: m.padStart(2, '0'),
        s: s.padStart(2, '0'),
    };
}

function buildTimeString(parts: TimeParts, fmt: TimeFormat): string {
    if (fmt === 'HH') return parts.h;
    if (fmt === 'HH:mm') return `${parts.h}:${parts.m}`;
    return `${parts.h}:${parts.m}:${parts.s}`;
}

function applyTimeToDate(base: Date, parts: TimeParts): Date {
    const d = new Date(base);
    d.setHours(Number(parts.h), Number(parts.m), Number(parts.s), 0);
    return d;
}

function dateToTimeParts(d: Date): TimeParts {
    return {
        h: d.getHours().toString().padStart(2, '0'),
        m: d.getMinutes().toString().padStart(2, '0'),
        s: d.getSeconds().toString().padStart(2, '0'),
    };
}

function formatDateDisplay(d: Date, showTime: boolean, fmt: TimeFormat): string {
    const datePart = format(d, 'dd/MM/yyyy');
    if (!showTime) return datePart;
    if (fmt === 'HH') return `${datePart} ${format(d, 'HH')}h`;
    if (fmt === 'HH:mm') return `${datePart} ${format(d, 'HH:mm')}`;
    return `${datePart} ${format(d, 'HH:mm:ss')}`;
}

function padOptions(count: number) {
    return Array.from({ length: count }, (_, i) => ({
        label: i.toString().padStart(2, '0'),
        value: i.toString().padStart(2, '0'),
    }));
}

const hoursOptions = padOptions(24);
const minutesOptions = padOptions(60);
const secondsOptions = padOptions(60);

// ---------- styles ----------

const popoverContent = tv({
    base: 'z-50  rounded-xl border border-border bg-background text-foreground shadow-xl outline-none data-open:animate-in data-closed:animate-out data-closed:fade-out-0 data-open:fade-in-0 data-closed:zoom-out-95 data-open:zoom-in-95 data-side-bottom:slide-in-from-top-2 data-side-left:slide-in-from-right-2 data-side-right:slide-in-from-left-2 data-side-top:slide-in-from-bottom-2',
});

// ---------- sub-components ----------

interface NativeSelectProps {
    value: string;
    options: { label: string; value: string }[];
    onChange: (val: string) => void;
    'aria-label'?: string;
}

const NativeScrollSelect: React.FC<NativeSelectProps> = ({ value, options, onChange, 'aria-label': ariaLabel }) => (
    <select
        aria-label={ariaLabel}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="h-9 w-full rounded-md border border-border bg-background px-2 text-sm text-foreground focus:border-primary focus:outline-none"
    >
        {options.map((o) => (
            <option key={o.value} value={o.value}>{o.label}</option>
        ))}
    </select>
);

interface TimePickerProps {
    parts: TimeParts;
    onChange: (parts: TimeParts) => void;
    timeFormat: TimeFormat;
    timePickerStyle: TimePickerStyle;
}

const TimePicker: React.FC<TimePickerProps> = ({ parts, onChange, timeFormat, timePickerStyle }) => {
    const showMinutes = timeFormat === 'HH:mm' || timeFormat === 'HH:mm:ss';
    const showSeconds = timeFormat === 'HH:mm:ss';

    if (timePickerStyle === 'input') {
        const inputType = timeFormat === 'HH:mm:ss' ? 'time' : 'time';

        // Native time input — giả lập với step
        const step = showSeconds ? 1 : 60;
        const rawValue = showSeconds
            ? `${parts.h}:${parts.m}:${parts.s}`
            : `${parts.h}:${parts.m}`;

        return (
            <input
                type="time"
                value={rawValue}
                step={step}
                onChange={(e) => {
                    const [h = '00', m = '00', s = '00'] = e.target.value.split(':');
                    onChange({ h: h.padStart(2, '0'), m: m.padStart(2, '0'), s: s.padStart(2, '0') });
                }}
                className="h-9 w-full rounded-md border border-border bg-background px-3 text-sm text-foreground focus:border-primary focus:outline-none"
            />
        );
    }

    return (
        <div className="flex items-center gap-1.5">
            <div className="flex-1">
                <NativeScrollSelect
                    aria-label="Giờ"
                    value={parts.h}
                    options={hoursOptions}
                    onChange={(val) => onChange({ ...parts, h: val })}
                />
            </div>
            {showMinutes && (
                <>
                    <span className="text-sm font-bold text-muted-foreground">:</span>
                    <div className="flex-1">
                        <NativeScrollSelect
                            aria-label="Phút"
                            value={parts.m}
                            options={minutesOptions}
                            onChange={(val) => onChange({ ...parts, m: val })}
                        />
                    </div>
                </>
            )}
            {showSeconds && (
                <>
                    <span className="text-sm font-bold text-muted-foreground">:</span>
                    <div className="flex-1">
                        <NativeScrollSelect
                            aria-label="Giây"
                            value={parts.s}
                            options={secondsOptions}
                            onChange={(val) => onChange({ ...parts, s: val })}
                        />
                    </div>
                </>
            )}
        </div>
    );
};

// ---------- main component ----------

export const DatePicker = React.forwardRef<HTMLDivElement, DatePickerProps>(({
    mode = 'single',
    date,
    onDateChange,
    onChange,
    timeValue,
    onTimeChange,
    label,
    placeholder = 'Chọn ngày...',
    disablePastDates = false,
    showTime = false,
    timeFormat = 'HH:mm:ss',
    timePickerStyle = 'select',
    disabled = false,
    className,
    description,
    error,
}, ref) => {
    const [open, setOpen] = React.useState(false);
    const triggerRef = React.useRef<HTMLButtonElement>(null);

    // Khởi tạo parts từ date prop hoặc timeValue
    const initParts = React.useMemo<TimeParts>(() => {
        if (mode === 'time-only' && timeValue) return parseTimeParts(timeValue);
        if (date instanceof Date) return dateToTimeParts(date);
        return DEFAULT_TIME;
    }, []);

    const [timeParts, setTimeParts] = React.useState<TimeParts>(initParts);

    // Sync khi prop thay đổi từ ngoài
    React.useEffect(() => {
        if (mode === 'time-only' && timeValue) {
            setTimeParts(parseTimeParts(timeValue));
        } else if (date instanceof Date) {
            setTimeParts(dateToTimeParts(date));
        }
    }, [date, timeValue, mode]);

    // Gọi callback khi timeParts thay đổi
    const handlePartsChange = (newParts: TimeParts) => {
        setTimeParts(newParts);
        if (mode === 'time-only') {
            onTimeChange?.(buildTimeString(newParts, timeFormat));
            return;
        }
        if (date instanceof Date) {
            const newDate = applyTimeToDate(date, newParts);
            onDateChange?.(newDate);
            onChange?.(newDate);
        }
    };

    const handleDateSelect = (selectedDate: Date | DateRange | Date[] | undefined) => {
        if (!selectedDate) {
            onDateChange?.(undefined);
            onChange?.(undefined);
            return;
        }
        if (mode === 'single' && showTime && selectedDate instanceof Date) {
            const newDate = applyTimeToDate(selectedDate, timeParts);
            onDateChange?.(newDate);
            onChange?.(newDate);
        } else {
            // Because of our mode checking, we can be confident here
            onDateChange?.(selectedDate as DateRange);
            onChange?.(selectedDate as DateRange);
        }
    };

    // ---------- render trigger label ----------
    const triggerLabel = React.useMemo(() => {
        if (mode === 'time-only') {
            const val = timeValue ?? buildTimeString(timeParts, timeFormat);
            if (!val || val === '00' || val === '00:00' || val === '00:00:00')
                return <span className="text-muted-foreground">{placeholder || 'Chọn giờ...'}</span>;
            return <span>{val}</span>;
        }

        if (!date) return <span className="text-muted-foreground">{placeholder}</span>;

        if (mode === 'single' && date instanceof Date) {
            return <span>{formatDateDisplay(date, showTime, timeFormat)}</span>;
        }

        if (mode === 'range') {
            const range = date as DateRange;
            if (range.from && range.to) {
                return (
                    <span>
                        {format(range.from, 'dd/MM/yyyy')} – {format(range.to, 'dd/MM/yyyy')}
                    </span>
                );
            }
            if (range.from) return <span>{format(range.from, 'dd/MM/yyyy')} –</span>;
        }

        return <span className="text-muted-foreground">{placeholder}</span>;
    }, [date, mode, showTime, timeFormat, timeValue, timeParts, placeholder]);

    const isTimeMode = mode === 'time-only';
    const needsTimePicker = isTimeMode || (mode === 'single' && showTime);

    return (
        <div ref={ref} className={`flex flex-col gap-1.5 w-full ${className || ''}`}>
            {label && (
                <label className="text-sm font-medium text-foreground leading-none">
                    {label}
                </label>
            )}

            <BasePopover.Root open={open} onOpenChange={disabled ? undefined : setOpen}>
                <BasePopover.Trigger
                    render={
                        <button
                            ref={triggerRef}
                            type="button"
                            disabled={disabled}
                            className={[
                                'flex h-10 w-full items-center gap-2 rounded-md border bg-background px-3 py-2 text-sm',
                                'ring-offset-background transition-shadow',
                                'hover:border-primary focus:border-primary focus:outline-none',
                                'disabled:cursor-not-allowed disabled:opacity-50',
                                error ? 'border-danger focus:border-danger' : 'border-border',
                                'group',
                            ].join(' ')}
                        >
                            {isTimeMode ? (
                                <Clock className="h-4 w-4 shrink-0 text-muted-foreground" />
                            ) : (
                                <CalendarIcon className="h-4 w-4 shrink-0 text-muted-foreground" />
                            )}
                            <div className="flex-1 truncate text-left">{triggerLabel}</div>
                            <ChevronDown className="h-4 w-4 shrink-0 text-muted-foreground transition-transform duration-200 group-data-open:rotate-180" />
                        </button>
                    }
                />

                <BasePopover.Portal>
                    <BasePopover.Positioner anchor={triggerRef} sideOffset={6} className="z-50">
                        <BasePopover.Popup className={popoverContent()}>
                            {!isTimeMode && mode === 'single' && (
                                <div className="p-2 flex justify-center">
                                    <DayPicker
                                        mode="single"
                                        locale={locales.vi}
                                        selected={date as Date | undefined}
                                        onSelect={(d) => handleDateSelect(d)}
                                        disabled={disablePastDates ? [{ before: new Date() }] : undefined}
                                        className="rdp-custom"
                                    />
                                </div>
                            )}
                            {!isTimeMode && mode === 'range' && (
                                <div className="p-2 flex justify-center">
                                    <DayPicker
                                        mode="range"
                                        locale={locales.vi}
                                        selected={date as DateRange | undefined}
                                        onSelect={(d) => handleDateSelect(d)}
                                        disabled={disablePastDates ? [{ before: new Date() }] : undefined}
                                        className="rdp-custom"
                                    />
                                </div>
                            )}

                            {/* Time picker */}
                            {needsTimePicker && (
                                <div className={`border-t border-border p-3 flex flex-col gap-2 ${isTimeMode ? 'border-t-0' : ''}`}>
                                    <div className="flex items-center gap-1.5 text-xs font-semibold text-muted-foreground uppercase tracking-wide">
                                        <Clock className="w-3.5 h-3.5" />
                                        <span>
                                            {timeFormat === 'HH' ? 'Chọn giờ' : timeFormat === 'HH:mm' ? 'Giờ : Phút' : 'Giờ : Phút : Giây'}
                                        </span>
                                    </div>
                                    <TimePicker
                                        parts={timeParts}
                                        onChange={handlePartsChange}
                                        timeFormat={timeFormat}
                                        timePickerStyle={timePickerStyle}
                                    />
                                </div>
                            )}

                            {/* Footer actions */}
                            <div className="flex items-center justify-between gap-2 p-3 border-t border-border">
                                <button
                                    type="button"
                                    onClick={() => {
                                        if (mode === 'time-only') {
                                            setTimeParts(DEFAULT_TIME);
                                            onTimeChange?.('');
                                        } else {
                                            onDateChange?.(undefined);
                                        }
                                    }}
                                    className="text-xs text-muted-foreground hover:text-foreground transition-colors underline-offset-2 hover:underline"
                                >
                                    Xóa
                                </button>
                                <Button size="sm" onClick={() => setOpen(false)}>
                                    Xác nhận
                                </Button>
                            </div>
                        </BasePopover.Popup>
                    </BasePopover.Positioner>
                </BasePopover.Portal>
            </BasePopover.Root>
            {description && !error && (
                <p className="text-[0.8rem] text-muted-foreground">{description}</p>
            )}
            {error && (
                <p className="text-[0.8rem] font-medium text-danger">{error}</p>
            )}
        </div>
    );
});

DatePicker.displayName = "DatePicker";

