export interface InputProps extends Omit<React.ComponentPropsWithoutRef<typeof BaseInput>, 'className'>, VariantProps<typeof inputVariants> {
  label?: string;
  error?: string;
  description?: string;
  icon?: React.ReactNode;
  endIcon?: React.ReactNode;
