import * as React from 'react';
import { tv, type VariantProps } from 'tailwind-variants';
import { Star } from 'lucide-react';

const rateVariants = tv({
  slots: {
    root: 'inline-flex items-center gap-0.5',
    star: 'relative cursor-pointer transition-transform duration-100 hover:scale-110 focus:outline-none focus-visible:ring-2 focus-visible:ring-primary rounded-sm',
    starIcon: 'transition-colors duration-150',
  },
  variants: {
    size: {
      sm: { star: 'w-4 h-4', starIcon: 'w-4 h-4' },
      md: { star: 'w-6 h-6', starIcon: 'w-6 h-6' },
      lg: { star: 'w-8 h-8', starIcon: 'w-8 h-8' },
      xl: { star: 'w-10 h-10', starIcon: 'w-10 h-10' },
    },
    readonly: {
      true: { star: 'cursor-default hover:scale-100' },
    },
  },
  defaultVariants: {
    size: 'md',
  },
});

export interface RateProps extends VariantProps<typeof rateVariants> {
  value?: number;
  defaultValue?: number;
  onChange?: (value: number) => void;
  count?: number;
  allowHalf?: boolean;
  allowClear?: boolean;
  readonly?: boolean;
  disabled?: boolean;
  character?: React.ReactNode;
  activeColor?: string;
  inactiveColor?: string;
  className?: string;
  'aria-label'?: string;
}

const Rate = React.forwardRef<HTMLDivElement, RateProps>(({
  value: controlledValue,
  defaultValue = 0,
  onChange,
  count = 5,
  allowHalf = false,
  allowClear = true,
  readonly = false,
  disabled = false,
  character,
  activeColor = 'text-amber-400',
  inactiveColor = 'text-muted-foreground/30',
  size,
  className,
  'aria-label': ariaLabel,
}, ref) => {
  const isControlled = controlledValue !== undefined;
  const [internalValue, setInternalValue] = React.useState(defaultValue);
  const [hoverValue, setHoverValue] = React.useState<number | null>(null);

  const value = isControlled ? controlledValue! : internalValue;

  const handleChange = (newVal: number) => {
    if (readonly || disabled) return;
    const next = allowClear && newVal === value ? 0 : newVal;
    if (!isControlled) setInternalValue(next);
    onChange?.(next);
  };

  const getStarFraction = (starIndex: number, displayValue: number): number => {
    const full = starIndex + 1;
    const half = starIndex + 0.5;
    if (displayValue >= full) return 1;
    if (allowHalf && displayValue >= half) return 0.5;
    return 0;
  };

  const slots = rateVariants({ size, readonly: readonly || disabled });
  const display = hoverValue ?? value;

  return (
    <div
      ref={ref}
      className={slots.root({ className })}
      role="radiogroup"
      aria-label={ariaLabel || 'Đánh giá'}
    >
      {Array.from({ length: count }, (_, i) => {
        const fraction = getStarFraction(i, display);
        const full = i + 1;
        const half = i + 0.5;

        const renderStar = (frac: number) => {
          if (character) {
            if (frac === 0.5) {
              return (
                <span className="relative inline-flex items-center justify-center w-full h-full">
                  <span className={`absolute inset-0 overflow-hidden ${inactiveColor}`}>{character}</span>
                  <span className="absolute inset-0 overflow-hidden w-1/2" style={{ color: 'inherit' }}>
                    <span className={activeColor}>{character}</span>
                  </span>
                </span>
              );
            }
            return <span className={frac === 1 ? activeColor : inactiveColor}>{character}</span>;
          }

          if (frac === 0.5) {
            return (
              <span className="relative inline-flex items-center justify-center w-full h-full">
                <Star className={`${slots.starIcon()} ${inactiveColor}`} fill="currentColor" />
                <span
                  className="absolute inset-0 overflow-hidden"
                  style={{ width: '50%' }}
                  aria-hidden="true"
                >
                  <Star className={`${slots.starIcon()} ${activeColor}`} fill="currentColor" />
                </span>
              </span>
            );
          }

          return (
            <Star
              className={`${slots.starIcon()} ${frac === 1 ? activeColor : inactiveColor}`}
              fill="currentColor"
            />
          );
        };

        return (
          <button
            key={i}
            type="button"
            role="radio"
            aria-checked={full <= value}
            aria-label={`${full} sao`}
            disabled={disabled}
            className={slots.star()}
            onMouseMove={(e) => {
              if (readonly || disabled) return;
              if (allowHalf) {
                const rect = e.currentTarget.getBoundingClientRect();
                const isLeft = e.clientX - rect.left < rect.width / 2;
                setHoverValue(isLeft ? half : full);
              } else {
                setHoverValue(full);
              }
            }}
            onMouseLeave={() => setHoverValue(null)}
            onClick={(e) => {
              if (readonly || disabled) return;
              if (allowHalf) {
                const rect = e.currentTarget.getBoundingClientRect();
                const isLeft = e.clientX - rect.left < rect.width / 2;
                handleChange(isLeft ? half : full);
              } else {
                handleChange(full);
              }
            }}
            onKeyDown={(e) => {
              if (readonly || disabled) return;
              if (e.key === 'ArrowRight' || e.key === 'ArrowUp') {
                e.preventDefault();
                handleChange(Math.min(count, value + (allowHalf ? 0.5 : 1)));
              } else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') {
                e.preventDefault();
                handleChange(Math.max(0, value - (allowHalf ? 0.5 : 1)));
              }
            }}
          >
            {renderStar(fraction)}
          </button>
        );
      })}
    </div>
  );
});

Rate.displayName = 'Rate';

export { Rate };

import * as React from 'react';
import { Select as BaseSelect } from '@base-ui/react';
import { tv } from 'tailwind-variants';
import { cn } from '@lib/utils/cn';
import { ChevronDown, Check, X } from 'lucide-react';

const selectVariants = tv({
    slots: {
        trigger: 'flex h-10 w-full items-center justify-between rounded-md border border-border bg-background px-3 py-2 text-sm ring-offset-background focus:border-primary focus:outline-none disabled:cursor-not-allowed disabled:opacity-50 transition-shadow group cursor-pointer',
        content: 'relative z-50 max-h-[300px] min-w-[var(--anchor-width)] overflow-hidden rounded-md border border-border bg-background text-foreground shadow-md data-open:animate-in data-closed:animate-out data-closed:fade-out-0 data-open:fade-in-0 data-closed:zoom-out-95 data-open:zoom-in-95 data-side-bottom:slide-in-from-top-2 data-side-left:slide-in-from-right-2 data-side-right:slide-in-from-left-2 data-side-top:slide-in-from-bottom-2',
        viewport: 'p-1',
        item: 'relative flex w-full cursor-default select-none items-center rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none focus:bg-muted focus:text-foreground data-disabled:pointer-events-none data-disabled:opacity-50 data-highlighted:bg-muted data-highlighted:text-foreground',
        icon: 'h-4 w-4 opacity-50 transition-transform duration-200 group-data-open:rotate-180',
    }
});

const { trigger, content, viewport, item, icon } = selectVariants();

export interface SelectProps extends Omit<React.ComponentPropsWithoutRef<typeof BaseSelect.Root>, 'value' | 'defaultValue'> {
    label?: string;
    description?: string;
    error?: string;
    placeholder?: string;
    options: { label: string; value: string }[];
    id?: string;
    className?: string;
    value?: string;
    defaultValue?: string;
    clearable?: boolean;
    onChange?: (value: string) => void;
    emptyText?: string;
    clearLabel?: string;
}

const Select = React.forwardRef<React.ElementRef<typeof BaseSelect.Trigger>, SelectProps>(
    ({ label, description, error, placeholder = 'Chọn...', options, id, className, clearable = true, onChange, onValueChange, value, defaultValue, emptyText = 'Không tìm thấy kết quả.', clearLabel = 'Xóa lựa chọn', ...props }, ref) => {
        const triggerRef = React.useRef<HTMLButtonElement>(null);

        const [selectedValue, setSelectedValue] = React.useState<string>(value ?? defaultValue ?? '');

        React.useEffect(() => {
            if (value !== undefined) setSelectedValue(value);
        }, [value]);

        const handleValueChange = (val: unknown) => {
            const strVal = val as string;
            setSelectedValue(strVal);
            onChange?.(strVal);
            // @ts-expect-error Base UI type mapping for onValueChange expects strict context which is internal
            onValueChange?.(strVal, {
                event: new Event('change')
            });
        };

        const handleClear = (e: React.MouseEvent) => {
            e.preventDefault();
            e.stopPropagation();
            setSelectedValue('');
            onChange?.('');
            // @ts-expect-error Base UI type mapping for onValueChange expects strict context which is internal
            onValueChange?.('', {
                event: new Event('change')
            });
        };

        const selectedLabel = options.find((o) => o.value === selectedValue)?.label;

        return (
            <div className="flex flex-col gap-1.5 w-full">
                {label && (
                    <label className="text-sm font-medium text-foreground leading-none">
                        {label}
                    </label>
                )}

                {/*
                  * Wrapper relative: nút X nằm NGOÀI BaseSelect.Trigger (absolute)
                  * → click X không bao giờ bubble lên Trigger → popup không mở
                  */}
                <div className="relative w-full">
                    <BaseSelect.Root
                        value={value}
                        defaultValue={defaultValue}
                        onValueChange={handleValueChange}
                        {...props}
                    >
                        <BaseSelect.Trigger
                            ref={(node) => {
                                triggerRef.current = node;
                                if (typeof ref === 'function') ref(node);
                                else if (ref) (ref as React.MutableRefObject<HTMLButtonElement | null>).current = node;
                            }}
                            className={trigger({ className: cn(className, error ? 'border-danger focus:border-danger' : '') })}
                            id={id}
                        >
                            <span className={selectedLabel ? 'text-foreground' : 'text-muted-foreground'}>
                                {selectedLabel ?? placeholder}
                            </span>
                            <BaseSelect.Icon>
                                <ChevronDown className={icon()} />
                            </BaseSelect.Icon>
                        </BaseSelect.Trigger>
                        <BaseSelect.Portal>
                            <BaseSelect.Positioner anchor={triggerRef} className="z-50" sideOffset={4}>
                                <BaseSelect.Popup className={content()}>
                                    <div className={viewport()}>
                                        {options.length === 0 ? (
                                            <div className="py-2 px-8 text-sm text-muted-foreground italic text-center">
                                                {emptyText}
                                            </div>
                                        ) : (
                                            options.map((option) => (
                                                <BaseSelect.Item key={option.value} value={option.value} className={item()}>
                                                    <BaseSelect.ItemIndicator className="absolute left-2 flex h-3.5 w-3.5 items-center justify-center">
                                                        <Check className="h-4 w-4" />
                                                    </BaseSelect.ItemIndicator>
                                                    <BaseSelect.ItemText>{option.label}</BaseSelect.ItemText>
                                                </BaseSelect.Item>
                                            ))
                                        )}
                                    </div>
                                </BaseSelect.Popup>
                            </BaseSelect.Positioner>
                        </BaseSelect.Portal>
                    </BaseSelect.Root>

                    {/* Nút X đặt NGOÀI Trigger, absolute position — click không bubble lên Trigger */}
                    {clearable && selectedValue && (
                        <button
                            type="button"
                            aria-label={clearLabel}
                            onMouseDown={handleClear}
                            className="cursor-pointer absolute right-8 top-1/2 -translate-y-1/2 flex h-5 w-5 items-center justify-center rounded-full text-muted-foreground hover:bg-red-50 hover:text-red-500 transition-colors z-10"
                        >
                            <X className="h-3 w-3" />
                        </button>
                    )}
                </div>

                {description && !error && (
                    <p className="text-[0.8rem] text-muted-foreground">{description}</p>
                )}
                {error && (
                    <p className="text-[0.8rem] font-medium text-danger">{error}</p>
                )}
            </div>
        );
    }
);

Select.displayName = 'Select';

export { Select };

import * as React from 'react';
import { NavLink } from 'react-router-dom';
import { PanelLeft, ChevronRight, ChevronsUpDown } from 'lucide-react';
import { tv } from 'tailwind-variants';
import { Popover as BasePopover } from '@base-ui/react';
import { Tooltip } from '../tooltip/Tooltip';
import { cn } from '@lib/utils/cn';

// ─── Constants ────────────────────────────────────────────────────────────────

const SIDEBAR_WIDTH_DEFAULT = 256; // px
const SIDEBAR_WIDTH_MIN = 160; // px
const SIDEBAR_WIDTH_MAX = 480; // px
const SIDEBAR_WIDTH_ICON = '4rem';
const MOBILE_BREAKPOINT = 768;

// ─── Context ──────────────────────────────────────────────────────────────────

type SidebarState = 'expanded' | 'collapsed';

interface SidebarContextValue {
  state: SidebarState;
  open: boolean;
  setOpen: (open: boolean) => void;
  toggleSidebar: () => void;
  isMobile: boolean;
  openMobile: boolean;
  setOpenMobile: (open: boolean) => void;
  sidebarWidth: number;
  setSidebarWidth: (w: number) => void;
}

const SidebarContext = React.createContext<SidebarContextValue | null>(null);

export function useSidebar() {
  const ctx = React.useContext(SidebarContext);
  if (!ctx) throw new Error('useSidebar must be used within SidebarProvider');
  return ctx;
}

// ─── Provider ─────────────────────────────────────────────────────────────────

export interface SidebarProviderProps {
  children: React.ReactNode;
  defaultOpen?: boolean;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  className?: string;
  style?: React.CSSProperties;
}

const SidebarProvider = React.forwardRef<HTMLDivElement, SidebarProviderProps>(
  ({ children, defaultOpen = true, open: controlledOpen, onOpenChange, className, style }, ref) => {
    const [isMobile, setIsMobile] = React.useState(false);
    const [openMobile, setOpenMobile] = React.useState(false);
    const [internalOpen, setInternalOpen] = React.useState(defaultOpen);
    const [sidebarWidth, setSidebarWidth] = React.useState(SIDEBAR_WIDTH_DEFAULT);

    const isControlled = controlledOpen !== undefined;
    const open = isControlled ? controlledOpen! : internalOpen;

    React.useEffect(() => {
      const check = () => setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
      check();
      window.addEventListener('resize', check);
      return () => window.removeEventListener('resize', check);
    }, []);

    const setOpen = React.useCallback(
      (val: boolean) => {
        if (!isControlled) setInternalOpen(val);
        onOpenChange?.(val);
      },
      [isControlled, onOpenChange]
    );

    const toggleSidebar = React.useCallback(() => {
      if (isMobile) setOpenMobile((v) => !v);
      else setOpen(!open);
    }, [isMobile, open, setOpen]);

    React.useEffect(() => {
      const onKey = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
          e.preventDefault();
          toggleSidebar();
        }
      };
      window.addEventListener('keydown', onKey);
      return () => window.removeEventListener('keydown', onKey);
    }, [toggleSidebar]);

    const state: SidebarState = open ? 'expanded' : 'collapsed';

    return (
      <SidebarContext.Provider
        value={{ state, open, setOpen, toggleSidebar, isMobile, openMobile, setOpenMobile, sidebarWidth, setSidebarWidth }}
      >
        <div
          ref={ref}
          data-sidebar-state={state}
          style={
            {
              '--sidebar-width': `${sidebarWidth}px`,
              '--sidebar-width-icon': SIDEBAR_WIDTH_ICON,
              ...style,
            } as React.CSSProperties
          }
          className={cn('group/sidebar-wrapper flex min-h-screen w-full has-data-[variant=inset]:bg-muted/30', className)}
        >
          {children}
        </div>
      </SidebarContext.Provider>
    );
  }
);
SidebarProvider.displayName = 'SidebarProvider';

// ─── SidebarTrigger ───────────────────────────────────────────────────────────

const SidebarTrigger = React.forwardRef<
  HTMLButtonElement,
  React.ButtonHTMLAttributes<HTMLButtonElement>
>(({ className, onClick, ...props }, ref) => {
  const { toggleSidebar } = useSidebar();
  return (
    <button
      ref={ref}
      type="button"
      data-sidebar="trigger"
      onClick={(e) => {
        toggleSidebar();
        onClick?.(e);
      }}
      className={cn('inline-flex items-center justify-center h-8 w-8 rounded-md text-muted-foreground hover:bg-muted hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary', className)}
      title="Toggle Sidebar (⌘B)"
      {...props}
    >
      <PanelLeft className="h-4 w-4" />
      <span className="sr-only">Toggle Sidebar</span>
    </button>
  );
});
SidebarTrigger.displayName = 'SidebarTrigger';

// ─── Sidebar ──────────────────────────────────────────────────────────────────

export interface SidebarProps extends React.HTMLAttributes<HTMLElement> {
  side?: 'left' | 'right';
  variant?: 'sidebar' | 'floating' | 'inset';
  collapsible?: 'offcanvas' | 'icon' | 'none';
}

const Sidebar = React.forwardRef<HTMLElement, SidebarProps>(
  ({ side = 'left', variant = 'sidebar', collapsible = 'icon', className, children, ...props }, ref) => {
    const { state, isMobile, openMobile, setOpenMobile, sidebarWidth } = useSidebar();

    if (collapsible === 'none') {
      return (
        <aside
          ref={ref}
          className={cn('flex h-screen flex-col bg-sidebar border-r border-sidebar-border', className)}
          style={{ width: SIDEBAR_WIDTH_DEFAULT }}
          {...props}
        >
          {children}
        </aside>
      );
    }

    if (isMobile) {
      return (
        <>
          {openMobile && (
            <div
              className="fixed inset-0 z-40 bg-black/50 backdrop-blur-sm"
              onClick={() => setOpenMobile(false)}
            />
          )}
          <aside
            ref={ref}
            className={cn(
              'fixed inset-y-0 z-50 flex flex-col bg-sidebar border-r border-sidebar-border shadow-xl',
              'transition-transform duration-300 ease-in-out',
              side === 'left' ? 'left-0' : 'right-0',
              openMobile
                ? 'translate-x-0'
                : side === 'left'
                ? '-translate-x-full'
                : 'translate-x-full',
              className
            )}
            style={{ width: sidebarWidth }}
            {...props}
          >
            {children}
          </aside>
        </>
      );
    }

    return (
      <aside
        ref={ref}
        data-state={state}
        data-collapsible={state === 'collapsed' ? collapsible : ''}
        data-variant={variant}
        data-side={side}
        className={cn(
          'group relative flex h-screen flex-col bg-sidebar text-sidebar-foreground',
          'border-r border-dashed border-sidebar-border',
          state === 'collapsed' && 'will-change-[width] transition-[width] duration-300 ease-in-out',
          'overflow-hidden shrink-0',
          state === 'collapsed' && collapsible === 'icon' ? 'w-(--sidebar-width-icon)' : 'w-(--sidebar-width)',
          className
        )}
        {...props}
      >
        {children}
      </aside>
    );
  }
);
Sidebar.displayName = 'Sidebar';

// ─── SidebarRail — drag handle để resize ──────────────────────────────────────

const SidebarRail = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => {
    const { state, setSidebarWidth, sidebarWidth } = useSidebar();
    const isDragging = React.useRef(false);
    const startX = React.useRef(0);
    const startWidth = React.useRef(0);

    const onMouseDown = React.useCallback(
      (e: React.MouseEvent) => {
        if (state === 'collapsed') return;
        isDragging.current = true;
        startX.current = e.clientX;
        startWidth.current = sidebarWidth;
        document.body.style.cursor = 'col-resize';
        document.body.style.userSelect = 'none';
      },
      [state, sidebarWidth]
    );

    React.useEffect(() => {
      const onMouseMove = (e: MouseEvent) => {
        if (!isDragging.current) return;
        const delta = e.clientX - startX.current;
        const next = Math.min(SIDEBAR_WIDTH_MAX, Math.max(SIDEBAR_WIDTH_MIN, startWidth.current + delta));
        setSidebarWidth(next);
      };

      const onMouseUp = () => {
        if (!isDragging.current) return;
        isDragging.current = false;
        document.body.style.cursor = '';
        document.body.style.userSelect = '';
      };

      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', onMouseUp);
      return () => {
        window.removeEventListener('mousemove', onMouseMove);
        window.removeEventListener('mouseup', onMouseUp);
      };
    }, [setSidebarWidth]);

    if (state === 'collapsed') return null;

    return (
      <div
        ref={ref}
        data-sidebar="rail"
        aria-label="Resize sidebar"
        onMouseDown={onMouseDown}
        className={cn(
          'absolute inset-y-0 right-0 z-20 w-1 cursor-col-resize',
          'group/rail flex items-center justify-center',
          'after:absolute after:inset-y-0 after:right-0 after:w-1',
          'hover:after:bg-primary/50 transition-colors duration-150',
          className
        )}
        {...props}
      >
      </div>
    );
  }
);
SidebarRail.displayName = 'SidebarRail';

