import * as React from 'react';
import { Slider as BaseSlider } from '@base-ui/react';
import { tv, type VariantProps } from 'tailwind-variants';
import { cn } from '@lib/utils/cn';

const sliderVariants = tv({
  slots: {
    root: 'relative flex w-full touch-none select-none items-center py-4 data-disabled:opacity-50 data-disabled:cursor-not-allowed',
    control: 'relative flex w-full items-center', 
    track: 'relative h-1.5 w-full grow overflow-hidden rounded-full bg-secondary data-disabled:bg-muted',
    indicator: 'absolute h-full bg-primary data-disabled:bg-muted-foreground/30',
    thumb: 'block h-5 w-5 rounded-full border-2 border-primary bg-background ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 data-disabled:border-muted-foreground data-disabled:bg-muted data-disabled:pointer-events-none',
  }
});

const { root, control, track, indicator, thumb } = sliderVariants();

export interface SliderProps extends React.ComponentPropsWithoutRef<typeof BaseSlider.Root> {
    className?: string;
}

const Slider = React.forwardRef<React.ElementRef<typeof BaseSlider.Root>, SliderProps>(
  ({ className, ...props }, ref) => (
    <BaseSlider.Root
      ref={ref}
      className={root({ className })}
      {...props}
    >
      {/* 1. Thêm BaseSlider.Control bọc ngoài */}
      <BaseSlider.Control className={control()}>
        
        <BaseSlider.Track className={track()}>
          <BaseSlider.Indicator className={indicator()} />
        </BaseSlider.Track>

        {/* 2. Đưa Thumb ra ngoài Track, đứng ngang hàng */}
        <BaseSlider.Thumb className={thumb()} />
        
      </BaseSlider.Control>
    </BaseSlider.Root>
  )
)
Slider.displayName = 'Slider';

export { Slider };

import * as React from 'react';
import { tv, type VariantProps } from 'tailwind-variants';

const spinnerVariants = tv({
  base: 'animate-spin rounded-full border-2 border-current border-t-transparent',
  variants: {
    size: {
      xs: 'h-3 w-3 border-[1.5px]',
      sm: 'h-4 w-4 border-2',
      md: 'h-6 w-6 border-2',
      lg: 'h-8 w-8 border-3',
      xl: 'h-12 w-12 border-4',
    },
    variant: {
      primary: 'text-primary',
      secondary: 'text-secondary',
      white: 'text-white',
      muted: 'text-muted-foreground',
    }
  },
  defaultVariants: {
    size: 'md',
    variant: 'primary'
  }
});

export interface SpinnerProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof spinnerVariants> {}

const Spinner = React.forwardRef<HTMLDivElement, SpinnerProps>(
  ({ className, size, variant, ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={spinnerVariants({ size, variant, className })}
        role="status"
        aria-label="Loading"
        {...props}
      >
        <span className="sr-only">Loading...</span>
      </div>
    );
  }
);

Spinner.displayName = 'Spinner';

export { Spinner };

import * as React from 'react';
import { Switch as BaseSwitch } from '@base-ui/react';
import { tv, type VariantProps } from 'tailwind-variants';
import { cn } from '@/lib/utils/cn';

const switchVariants = tv({
  slots: {
    root: 'group inline-flex h-6 w-11 shrink-0  items-center rounded-full border-2 border-transparent transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50 data-checked:bg-primary data-unchecked:bg-switch-background',
    thumb: 'pointer-events-none block h-5 w-5 rounded-full bg-background shadow-lg ring-0 transition-transform data-checked:translate-x-5 data-unchecked:translate-x-0',
  },
  variants: {
    size: {
      sm: {
        root: 'h-5 w-9',
        thumb: 'h-4 w-4 data-checked:translate-x-4',
      },
      md: {
        root: 'h-6 w-11',
        thumb: 'h-5 w-5 data-checked:translate-x-5',
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});



export interface SwitchProps
  extends Omit<BaseSwitch.Root.Props, 'className'>,
  VariantProps<typeof switchVariants> {
